# ═══════════════════════════════════════════════════════════════════════
# Controls which signal channels are active during recording.
#   video        — continuous video recording + event timeline (recommended)
#   default      — full multimodal (structural events + screenshot perception)
#   vision_only  — only screenshot perception; no structural events
LEAPFLOW_RECORDING_MODE=video

# ═══════════════════════════════════════════════════════════════════════
# Video Recording (active when LEAPFLOW_RECORDING_MODE=video)
# ═══════════════════════════════════════════════════════════════════════
# Capture FPS for screen recording (lower = smaller files, 5 is sufficient).
# LEAPFLOW_VIDEO_FPS=5
# Resolution scale factor (0.0-1.0). Default 0.75 = 75% of native resolution.
# LEAPFLOW_VIDEO_RESOLUTION_SCALE=0.75
# Video codec: h264 (hardware-accelerated on macOS).
# LEAPFLOW_VIDEO_CODEC=h264
# Max seconds per video segment file before auto-splitting.
# LEAPFLOW_VIDEO_MAX_SEGMENT_S=600
# Directory for video segment cache.
# LEAPFLOW_VIDEO_CACHE_DIR=~/.leapflow/cache/video

# ── Video Analysis ──
