# LEAPFLOW_VIDEO_L2_ENABLED=true
# LEAPFLOW_VIDEO_L3_ENABLED=true
# LEAPFLOW_VIDEO_MAX_L2_REQUESTS=10

# ── Video Segmentation ──
# LEAPFLOW_VIDEO_SEGMENTER_MIN_S=30
# LEAPFLOW_VIDEO_SEGMENTER_MAX_S=600
# LEAPFLOW_VIDEO_SEGMENTER_IDLE_GAP_S=15
# LEAPFLOW_VIDEO_SEGMENTER_APP_GAP_S=5

